    public func withdraw(from accountID: UUID, amount: Money, reference: String, authorizationToken: String) {
        let tx = Transaction(type: .withdrawal, fromAccountID: accountID, toAccountID: nil, amount: amount, reference: reference)
        submit(tx, authorizationToken: authorizationToken)
    }

    public func transfer(from sourceID: UUID, to destinationID: UUID, amount: Money, reference: String, authorizationToken: String) {
        let tx = Transaction(type: .transfer, fromAccountID: sourceID, toAccountID: destinationID, amount: amount, reference: reference)
