                let loadedAccounts = await processor.fetchAccounts()
                let loadedTransactions = await processor.fetchTransactions()
                self.accounts = loadedAccounts
                self.transactions = loadedTransactions
            } catch {
                self.errorMessage = error.localizedDescription
            }
